20	    // === Token Management ===
21	    setToken(token: string): void {
22	        localStorage.setItem('token', token);
23	    }
24	
25	    getToken(): string | null {
26	        return localStorage.getItem('token');
27	    }
28	
29	    clearToken(): void {
30	        localStorage.removeItem('token');
31	    }
32	
33	    // === Headers ===
34	    getAuthHeaders(): HttpHeaders {
35	        const token = this.getToken();
36	        return new HttpHeaders().set('Authorization', token || '');
37	    }
38	
39	    setUserAuth(token) {
40	        token = localStorage.getItem("token")
41	        const headers = new HttpHeaders()
42	            .set('Authorization', token)
43	        return headers
44	    }
45	
46	    async isAuthenticated() {
47	        const token = localStorage.getItem('token');
48	        // Check whether the token is expired and return
49	        // true or false
50	        let isvalid = await this.verifyToken(token)
51	
52	        return isvalid;
53	    }
54	    async verifyToken(token): Promise<boolean> {
55	        let isvalid = <boolean>await new Promise((resolve, reject) => {
56	            this.http.get(this.serverAddress + `/verifyToken`, { headers: this.setUserAuth(token) }).subscribe((data: any) => {
57	                if (data.status == "success" && !this.jwtHelper.isTokenExpired(token)) {
58	                    resolve(true);
59	                }
60	                else {
61	                    resolve(false);
62	                }
63	            })
64	        })
65	        return isvalid;
66	    }
67	
68	    async getUserFromToken(): Promise<boolean> {
69	        const token = localStorage.getItem('token');
70	        if (token) {
71	            try {
72	                return decode(token);
73	            } catch {
74	                return null;
75	            }
76	        }
77	        return null;
78	    }
79	
80	    // === Logout ===
81	    logout(redirectUrl: string = '/login', message?: string): void {
82	        this.clearToken();
83	        if (message) {
84	            this.showLogoutNotification(message);
85	        }
86	        this.router.navigate([redirectUrl]);
87	    }
88	
89	    private showLogoutNotification(message: string): void {
90	        this._snackBar.open(message, 'OK', {
91	            duration: 5000, // 5 seconds
92	            panelClass: ['logout-snackbar'], // Optional custom styling
93	            horizontalPosition: 'center',
94	            verticalPosition: 'top'
95	        });
96	    }
97	}
